SELECT ORDERH.REF AS id, ORDERH.QTRESULTORDERREF AS original_quote_id, ORDERI.EXTRATYPE AS extra_type, ORDERI.QUANTITY, ORDERI.PRICE, ORDERI.LINE as line_num, ORDERI.UF_LOCKPRICE AS fixed_price, LEFT(PRODUCT.CODE, 1) + 'UK' AS BRAND_CODE, LEFT(PRODUCT.GROUP, 2) + 'UK' AS MAIN_GROUP_CODE, LEFT(PRODUCT.GROUP, 4) + 'UK' AS SUB_GROUP_CODE, LEFT(PRODUCT.GROUP, 6) + 'UK' AS SUB_SUB_GROUP_CODE, ORDERI.DESC1 as doc_prod_desc1, NIINGRED.NIBRAND, NIINGRED.NILDESC, PRODUCT.CODE, PRODUCT.CUNIT, PRODUCT.GROUP, PRODUCT.UF_IBARCODE, PRODUCT.UF_O_BARCODE, PRODUCT.UF_PRE_PRICED, PRODUCT.MASSNET, PRODUCT.MASSGROSS, PRODUCT.VOL, PRODUCT.COMMOD, PRODUCT.UF_CSSPALLET, PRODUCT.UF_CSSLAYER, PRODUCT.UF_BBEROTDATE, PRODUCT.UF_WH_SHELF, PRODUCT.PRUSER01, PRODUCT.PRUSER02, PRODUCT.PRUSER03 FROM ORDERI JOIN PRODUCT ON ORDERI.PRODUCT = PRODUCT.CODE JOIN ORDERH ON ORDERI.REF = ORDERH.REF LEFT JOIN NIINGRED ON PRODUCT.UF_IBARCODE = NIINGRED.NIEAN AND NIINGRED.NILDESC IS NOT NULL AND NIINGRED.NILANG = 'ENGLISH' WHERE ORDERI.REF = ?;
